={{
(() => {
  // Sécurisation HTML
  const esc = s => String(s ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

  // Extraction des données
  const b = $json.body || {};
  const c = b.customer || {};
  const items = b.items && Array.isArray(b.items) && b.items.length > 0 ? b.items : [{}];
  const item = items[0];

  const fullName = esc(c.name || 'Client');
  const phone    = esc(c.phone || 'Non renseigné');
  const orderNum = esc(b.order_number || '—');
  const total    = esc(b.total_amount || '0');
  const itemName = esc(item.product_title || 'Article non spécifié');
  const imgUrl   = item.image || '';

// LE VRAI LIEN DE PRODUCTION EN DUR
const valUrl = `https://koktek.com/admin?validate_order=${$json.body.order_number}`;

  // LE LIEN LOCALHOST POUR TES TESTS
  const localUrl = `http://localhost:5173/validation-vendeur?order=${orderNum}`;

  // Génération de la date
  const pad = n => String(n).padStart(2,'0');
  const d = new Date();
  const dd = pad(d.getDate()), mm = pad(d.getMonth()+1), yyyy = d.getFullYear();
  const hh = pad(d.getHours()), mi = pad(d.getMinutes());
  const h  = mi === '00' ? `${hh}h` : `${hh}h${mi}`;
  const dateStr = `${dd}-${mm}-${yyyy} ${h}`;

  // Construction du message
  const L = [];

  // 1. Le Titre tout en haut
  L.push('🛍️ <b>NOUVELLE COMMANDE EN ESPÈCES</b>\n');

  // 2. L'image (Lien invisible)
  if (imgUrl) {
     L.push(`<a href="${imgUrl}">&#8205;</a>`);
  }

  // 3. Le bloc des informations (calé à gauche)
  L.push(`<blockquote><b>Client :</b> ${fullName}`);
  L.push(`<b>Tél :</b> ${phone}\n`);
  L.push(`<b>Article :</b> <i>${itemName}</i>`);
  L.push(`<b>Total à encaisser :</b> <b>${total} €</b></blockquote>\n`);

  // 4. Le lien de validation
  L.push(`<a href="${valUrl}"><b>Attendez d'encaisser le client avant de valider.</b></a>\n`);

  // 5. La ligne de pointillés pour marquer le footer
  L.push(`┈┈┈┈┈┈┈┈┈┈┈┈┈┈┈┈┈┈┈┈┈┈┈┈`);

  // 6. Le Footer
  L.push(`Numéro de commande : ${orderNum}`);
  L.push(`Date de commande : ${dateStr}\n`);

  // 7. ASTUCE TEST LOCAL (À supprimer avant la mise en ligne)
  L.push(`<i>🔗 Lien Local (à copier) : ${localUrl}</i>`);

  return L.join('\n');
})()
}}
